To avoid confusion with the Enum type, I try to demonstrate the Dict problem with a simpler example:

```
class IntegerString(Integer):
    """Integer type that dumps to / loads from a string."""

    def dump(self, value):
        return str(value)

    def load(self, data):
        return int(data)


intdict = Dict(key_type=IntegerString(), value_types={1: String(), 2: String()})

dumped = intdict.dump({1: 'First', 2: 'Second'})
print(dumped)   # {'1': 'First', '2': 'Second'}
# The dump works as expected: key and values are dumped correctly.

loaded = intdict.load(dumped)
print(loaded)   # {}
# Oops, the values are lost. This is because the lookup of the value_types is
# done with the dumped keys '1' and '2', instead of the original keys 1 and 2.
```

The solution that works for me:

```
class Dict(Type):

    def load(self, data, *args, **kwargs):
        if data is MISSING or data is None:
            self._fail('required')

        if not is_mapping(data):
            self._fail('invalid')

        errors_builder = ValidationErrorBuilder()
        result = {}
        for k, v in iteritems(data):
            # First, load the key to its original type.
            try:
                k = self.key_type.load(k, *args, **kwargs)
            except ValidationError as ve:
                errors_builder.add_error(k, ve.messages)

            # Now, lookup the value type.
            value_type = self.value_types.get(k)
            if value_type is None:
                continue

            try:
                result[k] = value_type.load(v, *args, **kwargs)
            except ValidationError as ve:
                errors_builder.add_error(k, ve.messages)

        errors_builder.raise_errors()

        return result
        
```

