You don't need to rewrite everything. There is another workaround which boils down to adapt `unittest.TestCase` to work like `pytest_twisted`.

The work required to make it work is the following:

- Use `unittest.TestCase.setUpClass` to setup the greenlet with a reactor
- When you want to run a test method, call it with `call_func_in_twisted_greenlet` which in terms call the magic `blockon` function. Also call `setUp` and `tearDown` using that function.
- If the `reactor` is still running stop it.

```python
import sys
import unittest

import greenlet

from twisted.python import failure
from twisted.internet import reactor
from twisted.internet import defer
from pytest_twisted.plugin import gr_twisted
from pytest_twisted.plugin import blockon
from pytest_twisted.plugin import pytest_pyfunc_call


def call_func_in_twisted_greenlet(func):
	if gr_twisted.dead:
		raise RuntimeError("twisted reactor has stopped")
	d = defer.Deferred()
	reactor.callLater(0.0, lambda: defer.maybeDeferred(func).chainDeferred(d))
	blockon(d)
	return True


class TwistedTestCase(unittest.TestCase):

	@classmethod
	def setUpClass(cls):
		global gr_twisted
		gr_twisted = greenlet.greenlet(reactor.run)
		failure.Failure.cleanFailure = lambda self: None  # give me better tracebacks

	@classmethod
	def tearDownClass(cls):
		if gr_twisted:
			reactor.stop()
			gr_twisted.switch()

	def run(self, result=None):
		orig_result = result
		if result is None:
			result = self.defaultTestResult()
			startTestRun = getattr(result, 'startTestRun', None)
			if startTestRun is not None:
				startTestRun()

		self._resultForDoCleanups = result
		result.startTest(self)

		testMethod = getattr(self, self._testMethodName)
		if (getattr(self.__class__, "__unittest_skip__", False) or
			getattr(testMethod, "__unittest_skip__", False)):
			# If the class or method was skipped.
			try:
				skip_why = (getattr(self.__class__, '__unittest_skip_why__', '')
							or getattr(testMethod, '__unittest_skip_why__', ''))
				self._addSkip(result, skip_why)
			finally:
				result.stopTest(self)
			return
		try:
			success = False
			try:
				call_func_in_twisted_greenlet(self.setUp)
			except unittest.SkipTest as e:
				self._addSkip(result, str(e))
			except KeyboardInterrupt:
				raise
			except:
				result.addError(self, sys.exc_info())
			else:
				try:
					call_func_in_twisted_greenlet(testMethod)
				except KeyboardInterrupt:
					raise
				except self.failureException:
					result.addFailure(self, sys.exc_info())
				except _ExpectedFailure as e:
					addExpectedFailure = getattr(result, 'addExpectedFailure', None)
					if addExpectedFailure is not None:
						addExpectedFailure(self, e.exc_info)
					else:
						warnings.warn("TestResult has no addExpectedFailure method, reporting as passes",
									  RuntimeWarning)
						result.addSuccess(self)
				except _UnexpectedSuccess:
					addUnexpectedSuccess = getattr(result, 'addUnexpectedSuccess', None)
					if addUnexpectedSuccess is not None:
						addUnexpectedSuccess(self)
					else:
						warnings.warn("TestResult has no addUnexpectedSuccess method, reporting as failures",
									  RuntimeWarning)
						result.addFailure(self, sys.exc_info())
				except unittest.SkipTest as e:
					self._addSkip(result, str(e))
				except:
					result.addError(self, sys.exc_info())
				else:
					success = True

				try:
					call_func_in_twisted_greenlet(self.tearDown)
				except KeyboardInterrupt:
					raise
				except:
					result.addError(self, sys.exc_info())
					success = False

			cleanUpSuccess = self.doCleanups()
			success = success and cleanUpSuccess
			if success:
				result.addSuccess(self)
		finally:
			result.stopTest(self)
			if orig_result is None:
				stopTestRun = getattr(result, 'stopTestRun', None)
				if stopTestRun is not None:
					stopTestRun()


class TestCase(TwistedTestCase):

	@defer.inlineCallbacks
	def test_silent_error(self):
		yield 1
		import pdb; pdb.set_trace()
		self.assertTrue(False)
```

