from kinto.core.events import BeforeResourceChanged

def add_metadata(record):
    record['original'] = {
                'filename': record['filename'],
                'hash': sha256(record['filecontent']),
                'mimetype': record['mimetype'],
                'size': len(record['filecontent']),
            }
  

def on_before_resource_changed(event):
    for record in event.impacted_records:
